('computer-science:2-4-1-boolean-logic:match:c5f5c4c1', 'computer-science', 'computer-science:2-4-1-boolean-logic', '2.4.1 Boolean Logic', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “NOT gate”?", "options": ["Another name for a NOT gate", "Outputs 1 when at least one input is 1", "Alternative notation for A AND B", "Has one input and outputs the opposite value"]}'::jsonb, '{"answer": 3, "explain": "“NOT gate” means: Has one input and outputs the opposite value"}'::jsonb),
('computer-science:2-4-1-boolean-logic:match:0eb0a658', 'computer-science', 'computer-science:2-4-1-boolean-logic', '2.4.1 Boolean Logic', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Truth table”?", "options": ["Show which gate is worked out first", "Another name for a NOT gate", "A truth table with 4 rows", "A table of every input combination and its output"]}'::jsonb, '{"answer": 3, "explain": "“Truth table” means: A table of every input combination and its output"}'::jsonb),
('computer-science:2-4-1-boolean-logic:match:96569dde', 'computer-science', 'computer-science:2-4-1-boolean-logic', '2.4.1 Boolean Logic', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Boolean expression”?", "options": ["Alternative notation for A OR B", "Show which gate is worked out first", "Outputs 1 when at least one input is 1", "A circuit written in text, e.g. Q = A AND B"]}'::jsonb, '{"answer": 3, "explain": "“Boolean expression” means: A circuit written in text, e.g. Q = A AND B"}'::jsonb),
('computer-science:2-4-1-boolean-logic:match:4d0fb549', 'computer-science', 'computer-science:2-4-1-boolean-logic', '2.4.1 Boolean Logic', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “2 inputs”?", "options": ["A table of every input combination and its output", "Alternative notation for NOT A", "Has one input and outputs the opposite value", "A truth table with 4 rows"]}'::jsonb, '{"answer": 3, "explain": "“2 inputs” means: A truth table with 4 rows"}'::jsonb),
