('computer-science:2-4-1-boolean-logic:match:087f574f', 'computer-science', 'computer-science:2-4-1-boolean-logic', '2.4.1 Boolean Logic', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bar over A”?", "options": ["A truth table with 4 rows", "Outputs 1 only when both inputs are 1", "Alternative notation for NOT A", "A truth table with 8 rows"]}'::jsonb, '{"answer": 2, "explain": "“Bar over A” means: Alternative notation for NOT A"}'::jsonb),
