('computer-science:2-5-1-languages:match:42a7e55a', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “High-level language”?", "options": ["Written in English-like keywords, portable, and easier for humans to read, write and debug", "Specific to one type of processor; either machine code or assembly language", "Binary instructions — the only language a CPU can run directly", "Able to be translated to run on many different types of processor"]}'::jsonb, '{"answer": 0, "explain": "“High-level language” means: Written in English-like keywords, portable, and easier for humans to read, write and debug"}'::jsonb),
('computer-science:2-5-1-languages:match:2f680747', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Low-level language”?", "options": ["A short abbreviation used in assembly language to represent one machine-code instruction", "Software that converts source code into machine code so a CPU can run it", "Binary instructions — the only language a CPU can run directly", "Specific to one type of processor; either machine code or assembly language"]}'::jsonb, '{"answer": 3, "explain": "“Low-level language” means: Specific to one type of processor; either machine code or assembly language"}'::jsonb),
('computer-science:2-5-1-languages:match:5c914eee', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Machine code”?", "options": ["Translates the whole program at once, producing a separate executable file", "Translates and runs a program one statement at a time", "A short abbreviation used in assembly language to represent one machine-code instruction", "Binary instructions — the only language a CPU can run directly"]}'::jsonb, '{"answer": 3, "explain": "“Machine code” means: Binary instructions — the only language a CPU can run directly"}'::jsonb),
('computer-science:2-5-1-languages:match:61268f8c', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Assembly language”?", "options": ["Binary instructions — the only language a CPU can run directly", "Short mnemonics, such as ADD or LDA, with a one-to-one relationship with machine code", "Specific to one type of processor; either machine code or assembly language", "A short abbreviation used in assembly language to represent one machine-code instruction"]}'::jsonb, '{"answer": 1, "explain": "“Assembly language” means: Short mnemonics, such as ADD or LDA, with a one-to-one relationship with machine code"}'::jsonb),
('computer-science:2-5-1-languages:match:d686bc3e', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Mnemonic”?", "options": ["A short abbreviation used in assembly language to represent one machine-code instruction", "Translates the whole program at once, producing a separate executable file", "The machine-code file produced by a compiler, which can run without the compiler present", "Binary instructions — the only language a CPU can run directly"]}'::jsonb, '{"answer": 0, "explain": "“Mnemonic” means: A short abbreviation used in assembly language to represent one machine-code instruction"}'::jsonb),
('computer-science:2-5-1-languages:match:24dcb238', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Translator”?", "options": ["Software that converts source code into machine code so a CPU can run it", "Specific to one type of processor; either machine code or assembly language", "The machine-code file produced by a compiler, which can run without the compiler present", "Binary instructions — the only language a CPU can run directly"]}'::jsonb, '{"answer": 0, "explain": "“Translator” means: Software that converts source code into machine code so a CPU can run it"}'::jsonb),
('computer-science:2-5-1-languages:match:8e70b756', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Compiler”?", "options": ["Translates the whole program at once, producing a separate executable file", "Short mnemonics, such as ADD or LDA, with a one-to-one relationship with machine code", "Software that converts source code into machine code so a CPU can run it", "Able to be translated to run on many different types of processor"]}'::jsonb, '{"answer": 0, "explain": "“Compiler” means: Translates the whole program at once, producing a separate executable file"}'::jsonb),
('computer-science:2-5-1-languages:match:5522a05e', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Interpreter”?", "options": ["Binary instructions — the only language a CPU can run directly", "A short abbreviation used in assembly language to represent one machine-code instruction", "Software that converts source code into machine code so a CPU can run it", "Translates and runs a program one statement at a time"]}'::jsonb, '{"answer": 3, "explain": "“Interpreter” means: Translates and runs a program one statement at a time"}'::jsonb),
('computer-science:2-5-1-languages:match:1cbfd7bd', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Executable file”?", "options": ["The machine-code file produced by a compiler, which can run without the compiler present", "Able to be translated to run on many different types of processor", "Translates the whole program at once, producing a separate executable file", "Translates and runs a program one statement at a time"]}'::jsonb, '{"answer": 0, "explain": "“Executable file” means: The machine-code file produced by a compiler, which can run without the compiler present"}'::jsonb),
('computer-science:2-5-1-languages:match:e8849dce', 'computer-science', 'computer-science:2-5-1-languages', '2.5.1 Languages', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Portable (of code)”?", "options": ["The machine-code file produced by a compiler, which can run without the compiler present", "Written in English-like keywords, portable, and easier for humans to read, write and debug", "Translates the whole program at once, producing a separate executable file", "Able to be translated to run on many different types of processor"]}'::jsonb, '{"answer": 3, "explain": "“Portable (of code)” means: Able to be translated to run on many different types of processor"}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:exam:2fe0db4b', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the IDE facility that colours keywords, strings and other parts of the code to show its structure.</p>", "options": ["Auto-complete", "Syntax highlighting", "A breakpoint", "The run-time environment"], "hint": "Which facility uses colour to show the structure of the code?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Syntax highlighting</strong></li></ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Only the correct option scores; 2 or more ticks scores 0.</li></ul>\n</div>", "modelAnswer": "Syntax highlighting."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:exam:fd0fe937', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to identify what a breakpoint does.</p>", "options": ["It deletes the line of code it is placed on", "It pauses the program at that line so it can be examined", "It suggests a variable name as the programmer types", "It translates the whole program into machine code"], "hint": "Think about what happens to the program when it reaches that line."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>It pauses the program at that line so it can be examined</strong></li></ul>\n</div>", "modelAnswer": "It pauses the program at that line so it can be examined."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:90546088', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "Which IDE facility colours keywords, strings and comments differently to make the code''s structure easier to read?", "options": ["Auto-complete", "Syntax highlighting", "A breakpoint", "The run-time environment"]}'::jsonb, '{"answer": 1, "explain": "Syntax highlighting colours different parts of the code so its structure is easy to see at a glance."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:586ef7c8', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "Which facility suggests variable and function names as the programmer types them?", "options": ["Auto-indentation", "Auto-complete", "A watch window", "The translator"]}'::jsonb, '{"answer": 1, "explain": "Auto-complete (code completion) suggests names as the programmer types, so they can be inserted quickly."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:f2bb6aa6', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "What is a syntax error?", "options": ["A mistake that breaks the grammar rules of the programming language", "A program that runs but produces the wrong output because of a mistake in the logic", "A message printed by the IDE to confirm the program ran successfully", "A tool used to pause a program at a chosen line while it is running"]}'::jsonb, '{"answer": 0, "explain": "A syntax error breaks the grammar rules of the language. A program that runs but gives the wrong result has a logic error instead."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:c6a8b12d', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "What is a logic error?", "options": ["A mistake that stops the program from being translated into machine code at all", "A mistake where the program runs but produces the wrong result", "A mistake that the IDE always underlines automatically as the code is typed", "A mistake that can only happen when a breakpoint has been set on the wrong line"]}'::jsonb, '{"answer": 1, "explain": "A logic error is grammatically correct code that runs but gives the wrong result. The IDE cannot flag these automatically like it can syntax errors."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:76ae3d88', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "What does a breakpoint let a programmer do?", "options": ["Pause the program at a chosen line so its state can be examined", "Automatically fix any syntax errors found in the program", "Colour the keywords in the code so they are easier to read", "Suggest the names of variables as they are being typed into the editor"]}'::jsonb, '{"answer": 0, "explain": "A breakpoint pauses the program at a chosen line so the programmer can examine what is happening at that point."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:6723e9cc', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "What does ''stepping'' through code let a programmer do?", "options": ["Delete lines of code one at a time until the error finally disappears completely", "Run the program one line at a time, watching what each line does", "Jump straight to the last line of the program without running any of the others", "Translate the whole program into machine code before it is run"]}'::jsonb, '{"answer": 1, "explain": "Stepping runs the program one line at a time, so the programmer can watch exactly what each line does."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:5b36451d', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "What does ''watching a variable'' mean in an IDE''s debugging tools?", "options": ["Seeing the variable''s current value as the program runs, to find where it becomes wrong", "Renaming the variable automatically to something more meaningful for the programmer to understand later", "Deleting the variable completely if it is never used anywhere else in the whole of the program", "Translating the variable''s value from one data type into a completely different one"]}'::jsonb, '{"answer": 0, "explain": "Watching variables shows their current values as the program runs, helping locate exactly where a value becomes wrong."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:c8822b5f', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "What does the run-time environment of an IDE allow?", "options": ["Running and testing the program from inside the IDE, seeing its output immediately", "Colouring different parts of the code to show its structure more clearly for the programmer", "Automatically indenting new lines of code to line up with the block they are inside", "Suggesting variable and function names as the programmer types them into the editor window"]}'::jsonb, '{"answer": 0, "explain": "The run-time environment lets the programmer run and test the program from inside the IDE and see its output straight away."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:8d546182', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "Which of these is a built-in translator that an IDE may provide?", "options": ["An auto-complete list of variable names shown as the programmer types", "A compiler or an interpreter", "A breakpoint marker placed on a chosen line of code", "A syntax highlighting colour scheme applied to the editor"]}'::jsonb, '{"answer": 1, "explain": "An IDE''s built-in translator is a compiler or an interpreter, letting code be translated and run without separate software."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:mcq:1abf6292', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'mcq', 'mcq', 1, '{"question": "A programmer wants to find exactly which line of their code causes a variable to hold the wrong value. Which combination of IDE tools is most useful?", "options": ["Auto-complete and auto-indentation", "Breakpoints, stepping and watching variables", "Syntax highlighting and the run-time environment", "The translator on its own, without using any other tool"]}'::jsonb, '{"answer": 1, "explain": "Breakpoints, stepping and watching variables together let the programmer see exactly where a value first goes wrong."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:tf:1211f10e', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'tf', 'tf', 1, '{"question": "Syntax highlighting colours different parts of the code to show its structure."}'::jsonb, '{"answer": true, "explain": "Correct — syntax highlighting colours keywords, strings and other elements so the code''s structure is easy to see."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:tf:77badfa1', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'tf', 'tf', 1, '{"question": "A logic error stops the program from running at all."}'::jsonb, '{"answer": false, "explain": "A logic error does NOT stop the program running — it runs but gives the wrong result. A syntax error is what breaks the language''s grammar rules."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:tf:6f8ad5e0', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'tf', 'tf', 1, '{"question": "Auto-complete suggests variable and function names as the programmer types."}'::jsonb, '{"answer": true, "explain": "Correct — auto-complete (code completion) suggests names to insert as you type."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:tf:e0b2ecf0', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'tf', 'tf', 1, '{"question": "A breakpoint permanently deletes the line of code it is placed on."}'::jsonb, '{"answer": false, "explain": "A breakpoint only pauses the program at that line — it does not delete or change any code."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:tf:87728b4f', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'tf', 'tf', 1, '{"question": "Stepping lets a programmer run the program one line at a time."}'::jsonb, '{"answer": true, "explain": "Correct — stepping runs the program one line at a time so the programmer can see what each line does."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:tf:92c6a2eb', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'tf', 'tf', 1, '{"question": "Watching variables means the IDE deletes any variable that is not used."}'::jsonb, '{"answer": false, "explain": "Watching variables shows the current value of chosen variables as the program runs — it does not delete anything."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:tf:5dfb0eb3', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'tf', 'tf', 1, '{"question": "The run-time environment lets a programmer run and test a program from inside the IDE."}'::jsonb, '{"answer": true, "explain": "Correct — the run-time environment means the programmer does not need separate software to run and test the program."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:tf:d1f4e63a', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'tf', 'tf', 1, '{"question": "An IDE cannot include a compiler or interpreter — these must always be separate programs."}'::jsonb, '{"answer": false, "explain": "An IDE''s built-in translator IS a compiler or an interpreter, letting code be translated and run from inside the IDE."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:learn:28ea2878', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'learn', 'mcq', 1, '{"readingTitle": "What is an IDE?", "reading": "<h4>Software that brings the tools together in one place</h4>\n<ul>\n<li>An <strong>IDE (Integrated Development Environment)</strong> is a piece of software that brings together, in <strong>one place</strong>, the tools a programmer needs to <strong>write</strong>, <strong>test</strong> and <strong>debug</strong> a program.</li>\n<li>Without an IDE, a programmer might have to swap between several separate pieces of software — one to type code, another to translate it, another to try and find mistakes. An IDE puts all of this together.</li>\n<li>Common facilities found in an IDE include an <strong>editor</strong> (with syntax highlighting, auto-indentation and auto-complete), tools that flag <strong>errors</strong> and help with <strong>debugging</strong>, a way to <strong>run</strong> the program, and a built-in <strong>translator</strong>.</li>\n</ul>", "question": "Which of these best describes an IDE (Integrated Development Environment)?", "options": ["A single language that a computer can understand directly, without any translation step at all", "Software that brings together the tools needed to write, test and debug a program in one place", "A type of computer built specially for running programmer software and nothing else", "A backup service that automatically saves a copy of a programmer''s code onto a separate remote server whenever a file is saved"]}'::jsonb, '{"answer": 1, "explain": "An IDE brings writing, testing and debugging tools together in one piece of software. It is not a language, a special computer, or a backup service."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:learn:08a39379', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'learn', 'mcq', 1, '{"readingTitle": "The editor and syntax highlighting", "reading": "<h4>Where you type your code — and how it helps you read it</h4>\n<ul>\n<li>The <strong>editor</strong> is the part of the IDE where the programmer <strong>types the code</strong>. It looks a little like a plain text editor, but it understands the programming language being used.</li>\n<li><strong>Syntax highlighting</strong> automatically colours different parts of the code — for example keywords, variable names, strings and comments are each shown in a different colour.</li>\n<li>This makes the <strong>structure</strong> of the code easier to see at a glance, and helps a mistake <strong>stand out</strong> — for example, if a string is not shown in the expected colour, a closing quote may be missing.</li>\n</ul>", "question": "How does syntax highlighting help a programmer while they write code?", "options": ["It automatically fixes every syntax and logic mistake in the code without any input at all from the programmer", "It colours keywords, strings and other parts of the code so the structure is clearer and mistakes stand out", "It translates the whole program from source code into machine code, ready for it to be run on the computer", "It saves a permanent backup copy of the code file onto a separate drive every time the programmer makes a change"]}'::jsonb, '{"answer": 1, "explain": "Syntax highlighting colours the code to show its structure and make mistakes easier to spot. It does not fix mistakes, translate code or make backups."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:learn:1ffa89b3', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'learn', 'mcq', 1, '{"readingTitle": "Auto-indentation and auto-complete", "reading": "<h4>Two more editor features that speed up writing code</h4>\n<ul>\n<li><strong>Auto-indentation</strong> automatically indents a new line to match the block it is inside — for example, the lines inside a loop or an if statement are indented for the programmer as they type, without them needing to press the tab key themselves.</li>\n<li><strong>Auto-complete</strong> (code completion) <strong>suggests</strong> variable names, function names and keywords as the programmer types, and lets them be inserted with a single key press.</li>\n<li>Together these features <strong>speed up writing code</strong> and <strong>reduce simple mistakes</strong>, such as inconsistent indentation or a misspelt variable name.</li>\n</ul>", "question": "What does auto-complete (code completion) do in an IDE?", "options": ["It automatically indents every single new line of code so it always lines up with the block it is inside it", "It suggests variable names, function names and keywords as the programmer types, so they can be inserted quickly", "It runs the finished program immediately, so the programmer can see exactly what output it produces on the screen", "It checks the whole of the program for every possible logic error before allowing the programmer to save the file"]}'::jsonb, '{"answer": 1, "explain": "Auto-complete suggests names as you type, speeding up writing and reducing typos. Auto-indentation (option 1) is a separate editor feature."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:learn:2beb5fdf', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'learn', 'mcq', 1, '{"readingTitle": "Spotting syntax errors as you type", "reading": "<h4>Catching mistakes before you even try to run the program</h4>\n<ul>\n<li>A <strong>syntax error</strong> is a mistake that breaks the grammar rules of the programming language — for example a missing bracket, a misspelt keyword, or a missing quotation mark.</li>\n<li>Most IDEs <strong>check the code as it is typed</strong> and flag a syntax error straight away, often by <strong>underlining</strong> it, so the programmer can fix the mistake immediately rather than only discovering it later when the program fails to run.</li>\n<li>This is different from a <strong>logic error</strong>, where the code is grammatically correct but does not do what the programmer intended. The IDE cannot flag these automatically, which is why <strong>debugging tools</strong> are needed instead (see below).</li>\n</ul>", "question": "Why is it useful for an IDE to flag syntax errors while the programmer is typing?", "options": ["It means the programmer never needs to test the finished program at all before it is given to anyone else to use", "It lets the programmer fix the mistake straight away, instead of only finding out when the program fails to run", "It automatically rewrites the programmer''s whole program so that it always produces the correct output", "It stops the programmer from being able to save their file until every single error has been fixed completely"]}'::jsonb, '{"answer": 1, "explain": "Flagging syntax errors as you type means mistakes can be fixed immediately, rather than only being found once the program is run."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:learn:06bcf03a', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'learn', 'mcq', 1, '{"readingTitle": "Debugging tools: breakpoints and stepping", "reading": "<h4>Pausing a program to see what is really happening</h4>\n<ul>\n<li>A <strong>logic error</strong> does not stop a program from running, but it does produce the wrong result — these are harder to find than syntax errors, so an IDE provides <strong>debugging tools</strong> to help track them down.</li>\n<li>A <strong>breakpoint</strong> is a marker placed on a chosen line of code. When the program runs, it <strong>pauses</strong> at that line instead of carrying straight on, so the programmer can look at what is happening at that point.</li>\n<li><strong>Stepping</strong> then lets the programmer run the program <strong>one line at a time</strong> from the breakpoint, watching exactly what each line does, instead of it all running at once.</li>\n</ul>", "question": "What does a breakpoint do when a program is run in an IDE?", "options": ["It permanently deletes the line of code it has been placed on before the program is even run at all", "It pauses the program at that line, so the programmer can look at what is happening at that point", "It highlights every syntax error found anywhere in the whole of the program''s code", "It automatically corrects any logic error found on that particular line of the program"]}'::jsonb, '{"answer": 1, "explain": "A breakpoint pauses the running program at a chosen line so the programmer can examine it. It does not delete code or fix errors."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:learn:1e05acab', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'learn', 'mcq', 1, '{"readingTitle": "Debugging tools: watching variables", "reading": "<h4>Seeing values change to find where it goes wrong</h4>\n<ul>\n<li>Once a program is paused at a breakpoint, or being stepped through, the programmer can <strong>watch variables</strong> — that is, see the <strong>current value</strong> of chosen variables at that point in the program.</li>\n<li>By watching how a variable''s value changes as each line runs, the programmer can spot the <strong>exact line</strong> where it becomes wrong, which usually shows where the logic error is.</li>\n<li>Used together, breakpoints, stepping and watching variables let a programmer <strong>debug more easily</strong> than by just reading the code and guessing.</li>\n</ul>", "question": "How does watching variables help a programmer find a logic error?", "options": ["It automatically corrects any variable that is holding an incorrect value while the program runs, without telling the programmer", "It shows the current value of chosen variables so the programmer can see exactly where a value first becomes wrong", "It permanently stops the program from ever being run again until the logic error has been found and fixed", "It highlights any keyword in the program that has been spelt incorrectly by the programmer while typing"]}'::jsonb, '{"answer": 1, "explain": "Watching variables shows their current values as the program runs, helping pinpoint the exact line where a value becomes wrong. It does not fix errors automatically."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:learn:c04e2435', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'learn', 'mcq', 1, '{"readingTitle": "Run-time environment and translators", "reading": "<h4>Running and translating the program without leaving the IDE</h4>\n<ul>\n<li>The <strong>run-time environment</strong> lets a programmer <strong>run (test) the program from inside the IDE</strong> and immediately see its output, instead of having to set up a separate piece of software to run it elsewhere.</li>\n<li>An IDE also includes a built-in <strong>translator</strong> — a <strong>compiler</strong> or an <strong>interpreter</strong> — so the source code can be <strong>translated and run directly within the IDE</strong>.</li>\n<li>Together, the run-time environment and the built-in translator mean a programmer can <strong>write, translate and test</strong> a program quickly, without switching between different pieces of software.</li>\n</ul>", "question": "What does the run-time environment of an IDE let a programmer do?", "options": ["Colour keywords and strings in different colours so the structure of the code is easier to read", "Run and test the program from inside the IDE and see its output straight away", "Pause the program at a chosen line so its variables can be inspected one at a time", "Automatically indent every new line of code so it lines up correctly with its block"]}'::jsonb, '{"answer": 1, "explain": "The run-time environment lets the programmer run and test the program from inside the IDE, without setting up separate software."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:misc:dd506219', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking an IDE is just a fancy text editor for typing code.</p><p><strong>✅ The correct idea:</strong> An IDE is more than an editor — it also provides <strong>error diagnostics</strong>, <strong>debugging tools</strong> (breakpoints, stepping, watching variables), a <strong>run-time environment</strong> to test the program, and a built-in <strong>translator</strong>, all in one place.</p>", "question": "Which of these is NOT normally provided by an IDE?", "options": ["Debugging tools such as breakpoints and stepping", "A word processor for writing essays and general documents", "A run-time environment for testing the program", "A built-in translator such as a compiler or an interpreter"]}'::jsonb, '{"answer": 1, "explain": "An IDE provides debugging tools, a run-time environment and a translator — not a general word processor for essays."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:misc:322fa582', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing a syntax error with a logic error.</p><p><strong>✅ The correct idea:</strong> A <strong>syntax error</strong> breaks the grammar rules of the language and is usually flagged by the IDE as you type. A <strong>logic error</strong> is grammatically correct code that runs but produces the <strong>wrong result</strong> — the IDE cannot flag these automatically, which is why debugging tools are needed.</p>", "question": "A program runs without any error message, but always calculates the wrong total. What type of error is this?", "options": ["A syntax error, because grammar mistakes always produce the wrong output when a program is run", "A logic error", "A translation error caused by a fault in the compiler or interpreter itself", "A run-time environment error caused by testing the program inside the IDE"]}'::jsonb, '{"answer": 1, "explain": "Running without an error message but giving the wrong result is the definition of a logic error, not a syntax error."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:misc:062c0f1e', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a breakpoint fixes the mistake for you.</p><p><strong>✅ The correct idea:</strong> A breakpoint only <strong>pauses</strong> the program at a chosen line — it does not fix anything. The programmer then uses <strong>stepping</strong> and <strong>watching variables</strong> to work out what has gone wrong and fix it themselves.</p>", "question": "What happens when a running program reaches a breakpoint?", "options": ["The program automatically fixes any mistake found on that line before carrying on", "The program pauses at that line so the programmer can examine it", "The program stops permanently and cannot be run again until it is rewritten", "The IDE deletes the breakpoint and continues running the rest of the program"]}'::jsonb, '{"answer": 1, "explain": "A breakpoint only pauses the program at that line — the programmer still has to find and fix the mistake themselves."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:misc:a0808682', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking auto-complete and syntax highlighting are the same feature.</p><p><strong>✅ The correct idea:</strong> <strong>Syntax highlighting</strong> colours the code so its structure is easier to read. <strong>Auto-complete</strong> is a different feature — it suggests names to insert as you type, saving time and reducing typos.</p>", "question": "Which feature suggests a variable name to insert as the programmer starts typing it?", "options": ["Syntax highlighting, because colouring the variable''s name is what suggests it should be used", "Auto-complete", "A breakpoint placed on the line where the variable is first declared", "The run-time environment used to test the finished program"]}'::jsonb, '{"answer": 1, "explain": "Auto-complete is the feature that suggests names as you type. Syntax highlighting only colours the code — it does not suggest anything."}'::jsonb),
('computer-science:2-5-2-the-integrated-development-environment-ide:misc:5bbefc74', 'computer-science', 'computer-science:2-5-2-the-integrated-development-environment-ide', '2.5.2 The Integrated Development Environment (IDE)', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking an IDE always needs a separate program to translate and run code.</p><p><strong>✅ The correct idea:</strong> An IDE has a built-in <strong>translator</strong> (a compiler or interpreter) and a <strong>run-time environment</strong>, so the programmer can translate and run their program <strong>from inside the IDE itself</strong> — no separate software is needed.</p>", "question": "Why can a programmer run and test their program without leaving the IDE?", "options": ["Because the IDE includes a built-in translator and a run-time environment for running the code", "Because the IDE automatically emails the finished program to a separate translating service every time it is saved", "Because every logic error in the program is fixed automatically the moment the program is first saved", "Because syntax highlighting alone translates the whole of the code into machine code as it is typed"]}'::jsonb, '{"answer": 0, "explain": "The IDE''s built-in translator and run-time environment mean the code can be translated and run from inside the IDE — no separate software is needed."}'::jsonb)
